### Step 6: `packages/client-generator-rest-api/src/render.ts`

This is the core code-generation module. It receives parsed DMMF data and emits TypeScript source as a string. There are no external dependencies beyond `@prisma/dmmf` types and the type mapper.

**Key decisions:**

- Enum kind fields are included in the model interface (their type is the enum name, which is also emitted as a union type alias).
- Relation fields (`kind === 'object'`) are skipped entirely. They do not appear in the interface.
- Unsupported fields (`kind === 'unsupported'`) are skipped entirely.
- The `id` field type is inferred by finding the field with `isId: true` in the model. If no such field exists (composite PK via `@@id`), we fall back to `unknown` and add a JSDoc note. The `findUnique` and `update` and `delete` methods reference this type.
- The class name for each model's client is `${ModelName}RestClient`.
- The overall exported class is `RestApiClient` with one property per model.
- `baseUrl` defaults to `/api` and is configurable.

```typescript
import type * as DMMF from '@prisma/dmmf'

import { mapFieldType } from './type-mapper'

// ────────────────────────────────────────────────────────────
// Helpers
// ────────────────────────────────────────────────────────────

function indent(text: string, spaces = 2): string {
  const pad = ' '.repeat(spaces)
  return text
    .split('\n')
    .map((line) => (line.length > 0 ? pad + line : line))
    .join('\n')
}

/**
 * Returns only the fields that should appear in the generated model interface:
 * - scalar fields (kind === 'scalar')
 * - enum fields (kind === 'enum')
 *
 * Relation fields (kind === 'object') and unsupported fields are excluded.
 */
function scalarAndEnumFields(model: DMMF.Model): DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

/**
 * Finds the TypeScript type of the @id field. Returns 'unknown' and emits
 * a comment if the model uses a composite primary key (@@id) with no single
 * @id field, since the REST route convention "GET /model/:id" does not
 * naturally map to composite keys.
 */
function getIdType(model: DMMF.Model): { type: string; hasId: boolean } {
  const idField = model.fields.find((f) => f.isId)
  if (!idField) {
    return { type: 'unknown', hasId: false }
  }
  return { type: mapFieldType(idField), hasId: true }
}

// ────────────────────────────────────────────────────────────
// Renderers
// ────────────────────────────────────────────────────────────

/**
 * Renders a single Prisma DatamodelEnum as a TypeScript union type.
 *
 * Example output:
 *   export type Role = 'ADMIN' | 'USER' | 'GUEST'
 */
export function renderEnum(dmmfEnum: DMMF.DatamodelEnum): string {
  if (dmmfEnum.values.length === 0) {
    return `export type ${dmmfEnum.name} = never\n`
  }
  const values = dmmfEnum.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${dmmfEnum.name} = ${values}\n`
}

/**
 * Renders a TypeScript interface for a single Prisma model.
 * Only scalar and enum fields are included.
 *
 * Example output:
 *   export interface User {
 *     id: number
 *     email: string
 *     name: string | null
 *     role: Role
 *     createdAt: string
 *   }
 */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = scalarAndEnumFields(model)
  if (fields.length === 0) {
    // Edge case: model with only relation or unsupported fields
    return `export interface ${model.name} {}\n`
  }
  const fieldLines = fields.map((f) => `${f.name}: ${mapFieldType(f)}`)
  const body = indent(fieldLines.join('\n'), 2)
  return `export interface ${model.name} {\n${body}\n}\n`
}

/**
 * Renders the CRUD client class for a single model.
 *
 * The class is named `${ModelName}RestClient`. It exposes:
 *   findMany, findUnique, create, update, delete
 *
 * All methods use the global fetch API for HTTP calls.
 * The resource path is the model name lowercased (e.g., User → /users).
 * The base URL is received from the outer RestApiClient and stored in
 * this.#baseUrl.
 *
 * Edge cases handled:
 *  - Models without a single @id field: findUnique, update, delete accept
 *    `id: unknown` and emit a JSDoc warning about composite keys.
 *  - Enum field types are referenced directly by name (they are emitted
 *    as union types at the top of the file).
 *  - The `create` data parameter uses Omit<Model, 'id'> only when there
 *    IS an @id field. Otherwise it uses the full interface.
 */
export function renderModelClient(model: DMMF.Model): string {
  const { type: idType, hasId } = getIdType(model)
  const modelName = model.name
  const resourcePath = `/${modelName.toLowerCase()}s`

  const createDataType = hasId ? `Omit<${modelName}, 'id'>` : modelName

  // Comment warning for composite-key models
  const compositeKeyWarning = hasId
    ? ''
    : `\n  /**\n   * Warning: this model uses a composite primary key (@@id).\n   * The id parameter type is 'unknown'. Adjust usage accordingly.\n   */`

  return `export class ${modelName}RestClient {
  readonly #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }
${compositeKeyWarning}
  async findMany(params?: {
    where?: Partial<${modelName}>
    take?: number
    skip?: number
  }): Promise<${modelName}[]> {
    const url = new URL(\`\${this.#baseUrl}${resourcePath}\`)
    if (params?.where) {
      url.searchParams.set('where', JSON.stringify(params.where))
    }
    if (params?.take !== undefined) {
      url.searchParams.set('take', String(params.take))
    }
    if (params?.skip !== undefined) {
      url.searchParams.set('skip', String(params.skip))
    }
    const res = await fetch(url.toString())
    if (!res.ok) {
      throw new Error(\`REST API error \${res.status}: \${await res.text()}\`)
    }
    return res.json() as Promise<${modelName}[]>
  }

  async findUnique(params: { where: { id: ${idType} } }): Promise<${modelName} | null> {
    const res = await fetch(\`\${this.#baseUrl}${resourcePath}/\${params.where.id}\`)
    if (res.status === 404) return null
    if (!res.ok) {
      throw new Error(\`REST API error \${res.status}: \${await res.text()}\`)
    }
    return res.json() as Promise<${modelName}>
  }

  async create(params: { data: ${createDataType} }): Promise<${modelName}> {
    const res = await fetch(\`\${this.#baseUrl}${resourcePath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) {
      throw new Error(\`REST API error \${res.status}: \${await res.text()}\`)
    }
    return res.json() as Promise<${modelName}>
  }

  async update(params: { where: { id: ${idType} }; data: Partial<${modelName}> }): Promise<${modelName}> {
    const res = await fetch(\`\${this.#baseUrl}${resourcePath}/\${params.where.id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) {
      throw new Error(\`REST API error \${res.status}: \${await res.text()}\`)
    }
    return res.json() as Promise<${modelName}>
  }

  async delete(params: { where: { id: ${idType} } }): Promise<${modelName}> {
    const res = await fetch(\`\${this.#baseUrl}${resourcePath}/\${params.where.id}\`, {
      method: 'DELETE',
    })
    if (!res.ok) {
      throw new Error(\`REST API error \${res.status}: \${await res.text()}\`)
    }
    return res.json() as Promise<${modelName}>
  }
}
`
}

/**
 * Renders the top-level RestApiClient class that aggregates all model clients.
 *
 * Example output:
 *   export class RestApiClient {
 *     readonly user: UserRestClient
 *     readonly post: PostRestClient
 *     constructor(options?: { baseUrl?: string }) {
 *       const baseUrl = options?.baseUrl ?? '/api'
 *       this.user = new UserRestClient(baseUrl)
 *       this.post = new PostRestClient(baseUrl)
 *     }
 *   }
 */
export function renderRestApiClient(models: DMMF.Model[]): string {
  const props = models
    .map((m) => `  readonly ${m.name.charAt(0).toLowerCase() + m.name.slice(1)}: ${m.name}RestClient`)
    .join('\n')

  const assignments = models
    .map((m) => {
      const propName = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      return `    this.${propName} = new ${m.name}RestClient(baseUrl)`
    })
    .join('\n')

  return `export class RestApiClient {
${props}

  constructor(options?: { baseUrl?: string }) {
    const baseUrl = options?.baseUrl ?? '/api'
${assignments}
  }
}
`
}

// ────────────────────────────────────────────────────────────
// Full file renderer
// ────────────────────────────────────────────────────────────

export interface RenderOptions {
  models: readonly DMMF.Model[]
  enums: readonly DMMF.DatamodelEnum[]
}

/**
 * Renders the complete generated TypeScript file contents as a string.
 * The output is a single self-contained file with no external runtime imports.
 */
export function renderGeneratedFile({ models, enums }: RenderOptions): string {
  const parts: string[] = []

  parts.push(
    '// This file was auto-generated by @prisma/client-generator-rest-api.\n' +
    '// Do not edit it manually.\n\n',
  )

  // 1. Enum type aliases
  if (enums.length > 0) {
    parts.push('// ── Enums ──────────────────────────────────────────────────\n\n')
    for (const e of enums) {
      parts.push(renderEnum(e))
    }
    parts.push('\n')
  }

  // 2. Model interfaces
  parts.push('// ── Model Interfaces ────────────────────────────────────────\n\n')
  for (const model of models) {
    parts.push(renderModelInterface(model))
    parts.push('\n')
  }

  // 3. Per-model CRUD client classes
  parts.push('// ── Model REST Clients ──────────────────────────────────────\n\n')
  for (const model of models) {
    parts.push(renderModelClient(model))
    parts.push('\n')
  }

  // 4. Top-level aggregator class
  parts.push('// ── Root Client ─────────────────────────────────────────────\n\n')
  parts.push(renderRestApiClient([...models]))

  return parts.join('')
}
```

