### Step 7: `packages/client-generator-rest-api/src/generate-client.ts`

This module bridges `GeneratorOptions` → `render.ts`. It reads the output path and `baseUrl` config, calls the renderer, and writes the file.

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { renderGeneratedFile } from './render'

const DEFAULT_OUTPUT_FILENAME = 'rest-client.ts'
const DEFAULT_BASE_URL = '/api'

export async function generateRestApiClient(options: GeneratorOptions): Promise<void> {
  const { generator, dmmf } = options

  if (!generator.output) {
    throw new Error(
      'An output path is required for the `rest-api-client` generator.\n' +
        'Please add an output option to your generator block:\n\n' +
        '  generator restClient {\n' +
        '    provider = "prisma-client-rest-api"\n' +
        '    output   = "./src/generated"\n' +
        '  }\n',
    )
  }

  const outputDir = parseEnvValue(generator.output)

  // User-configurable options from generator.config
  const configuredBaseUrl =
    typeof generator.config.baseUrl === 'string' ? generator.config.baseUrl : DEFAULT_BASE_URL

  // Ensure output directory exists
  await fs.mkdir(outputDir, { recursive: true })

  const content = renderGeneratedFile({
    models: dmmf.datamodel.models,
    enums: dmmf.datamodel.enums,
    baseUrl: configuredBaseUrl,
  })

  const outputFilePath = path.join(outputDir, DEFAULT_OUTPUT_FILENAME)
  await fs.writeFile(outputFilePath, content, 'utf-8')
}
```

Note: `baseUrl` is passed into `renderGeneratedFile` so the default value in the generated `RestApiClient` constructor reflects the configured value at code-gen time. This means `renderGeneratedFile`'s `RenderOptions` type also accepts `baseUrl?: string` and `renderRestApiClient` receives it. (The render module is the source of truth for the generated string; the generator just orchestrates I/O.)

Concretely, `RenderOptions` should be extended:

```typescript
export interface RenderOptions {
  models: readonly DMMF.Model[]
  enums: readonly DMMF.DatamodelEnum[]
  baseUrl?: string  // passed through to renderRestApiClient
}
```

And `renderGeneratedFile` threads it into `renderRestApiClient(models, baseUrl ?? '/api')`.

