### Step 8: `packages/client-generator-rest-api/src/generator.ts`

```typescript
import { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestApiClient } from './generate-client'

export class RestApiClientGenerator implements Generator {
  readonly name = 'prisma-client-rest-api'

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST API Client',
      defaultOutput: 'generated',
      requiresEngines: [],
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    await generateRestApiClient(options)
  }
}
```

Design notes:
- `name` is the string used in `provider = "prisma-client-rest-api"` in schema files.
- `defaultOutput` is `'generated'` (relative to the schema file location), consistent with the TS generator's behavior.
- No `requiresEngines` since this generator needs no query/schema engine — it purely reads DMMF.
- `_config` is unused in `getManifest` for this generator since the output path is validated lazily in `generate`. This is acceptable since the output requirement is schema-time configurable, matching the pattern in `client-generator-ts`.

