### Step 10: `packages/client-generator-rest-api/src/__tests__/render.test.ts`

The tests are pure unit tests: they construct minimal DMMF objects in-memory and assert on the rendered string output. No filesystem access, no generator invocation.

```typescript
import { describe, expect, it } from 'vitest'
import type * as DMMF from '@prisma/dmmf'

import {
  renderEnum,
  renderModelInterface,
  renderModelClient,
  renderRestApiClient,
  renderGeneratedFile,
} from '../render'

// ── Test fixtures ────────────────────────────────────────────

function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'id',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: true,
    isReadOnly: false,
    hasDefaultValue: true,
    type: 'Int',
    ...overrides,
  } as DMMF.Field
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as unknown as DMMF.Model
}

function makeEnum(name: string, values: string[]): DMMF.DatamodelEnum {
  return {
    name,
    values: values.map((v) => ({ name: v, dbName: null })),
  }
}

// ── renderEnum ────────────────────────────────────────────────

describe('renderEnum', () => {
  it('renders a union type alias for a simple enum', () => {
    const e = makeEnum('Role', ['ADMIN', 'USER', 'GUEST'])
    expect(renderEnum(e)).toMatchInlineSnapshot(`
      "export type Role = 'ADMIN' | 'USER' | 'GUEST'
      "
    `)
  })

  it('renders a never type for an empty enum', () => {
    const e = makeEnum('Empty', [])
    expect(renderEnum(e)).toMatchInlineSnapshot(`
      "export type Empty = never
      "
    `)
  })

  it('preserves enum member names without dbName transformation', () => {
    // dbName on enum values is a DB-level alias and should not affect generated TS
    const e: DMMF.DatamodelEnum = {
      name: 'MappedEnum',
      values: [
        { name: 'ADMIN', dbName: 'admin_role' },
        { name: 'USER', dbName: null },
      ],
    }
    expect(renderEnum(e)).toContain("'ADMIN'")
    expect(renderEnum(e)).toContain("'USER'")
    expect(renderEnum(e)).not.toContain('admin_role')
  })
})

// ── renderModelInterface ──────────────────────────────────────

describe('renderModelInterface', () => {
  it('renders a basic User interface', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'email', type: 'String', isId: false }),
      makeField({ name: 'name', type: 'String', isId: false, isRequired: false }),
    ])
    expect(renderModelInterface(model)).toMatchInlineSnapshot(`
      "export interface User {
        id: number
        email: string
        name: string | null
      }
      "
    `)
  })

  it('skips relation (object) fields', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'author', kind: 'object', type: 'User', isId: false }),
    ])
    const result = renderModelInterface(model)
    expect(result).not.toContain('author')
    expect(result).toContain('id')
  })

  it('skips unsupported fields', () => {
    const model = makeModel('Weird', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'legacy', kind: 'unsupported', type: 'Unsupported', isId: false }),
    ])
    const result = renderModelInterface(model)
    expect(result).not.toContain('legacy')
  })

  it('includes enum fields with the enum type name', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'role', kind: 'enum', type: 'Role', isId: false }),
    ])
    const result = renderModelInterface(model)
    expect(result).toContain('role: Role')
  })

  it('renders list fields as Array<T>', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'tags', type: 'String', isList: true, isId: false }),
    ])
    const result = renderModelInterface(model)
    expect(result).toContain('tags: Array<string>')
