The generated `src/generated/rest-client.ts` would look like:

```typescript
// This file was auto-generated by @prisma/client-generator-rest-api.
// Do not edit it manually.

// ── Enums ──────────────────────────────────────────────────

export type Role = 'ADMIN' | 'USER' | 'GUEST'

// ── Model Interfaces ────────────────────────────────────────

export interface User {
  id: number
  email: string
  name: string | null
  role: Role
  createdAt: string
}

