// ── Model REST Clients ──────────────────────────────────────

export class UserRestClient {
  readonly #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(params?: {
    where?: Partial<User>
    take?: number
    skip?: number
  }): Promise<User[]> {
    const url = new URL(`${this.#baseUrl}/users`)
    if (params?.where) {
      url.searchParams.set('where', JSON.stringify(params.where))
    }
    if (params?.take !== undefined) {
      url.searchParams.set('take', String(params.take))
    }
    if (params?.skip !== undefined) {
      url.searchParams.set('skip', String(params.skip))
    }
    const res = await fetch(url.toString())
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User[]>
  }

  async findUnique(params: { where: { id: number } }): Promise<User | null> {
    const res = await fetch(`${this.#baseUrl}/users/${params.where.id}`)
    if (res.status === 404) return null
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User>
  }

  async create(params: { data: Omit<User, 'id'> }): Promise<User> {
    const res = await fetch(`${this.#baseUrl}/users`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User>
  }

  async update(params: { where: { id: number }; data: Partial<User> }): Promise<User> {
    const res = await fetch(`${this.#baseUrl}/users/${params.where.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User>
  }

  async delete(params: { where: { id: number } }): Promise<User> {
    const res = await fetch(`${this.#baseUrl}/users/${params.where.id}`, {
      method: 'DELETE',
    })
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User>
  }
}

