### Step 5: `packages/client-generator-rest-api/src/type-mapper.ts`

This module is pure and stateless: given a DMMF `Field`, it returns the TypeScript type string.

```typescript
import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a Prisma scalar type name to its TypeScript equivalent for use
 * in the generated REST API client interfaces.
 *
 * Decimal and DateTime are represented as strings because they travel
 * over HTTP/JSON as strings and preserving their exact representation
 * in the client's interface makes the usage at call sites correct.
 *
 * Bytes is represented as a string because binary data is Base64-encoded
 * over HTTP/JSON.
 */
const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/**
 * Returns the TypeScript base type for a DMMF field (before list/nullability
 * wrapping). For enum fields, the enum name is returned directly because
 * the generator will emit a matching TypeScript union type for each enum.
 * For unsupported fields this function should never be called (they are
 * filtered out upstream), but 'unknown' is returned as a safe fallback.
 */
export function mapFieldBaseType(field: DMMF.Field): string {
  if (field.kind === 'enum') {
    return field.type
  }
  if (field.kind === 'scalar') {
    return SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  }
  // 'object' (relations) and 'unsupported' are filtered before this is called
  return 'unknown'
}

/**
 * Returns the full TypeScript type annotation string for a DMMF field,
 * including list and nullability handling.
 *
 * Convention used here:
 *  - Required list field:   Array<T>
 *  - Optional list field:   Array<T> | null
 *  - Required scalar field: T
 *  - Optional scalar field: T | null
 *
 * We always emit | null rather than T? on the interface property because
 * REST API payloads conventionally include the key with a null value rather
 * than omitting it.
 */
export function mapFieldType(field: DMMF.Field): string {
  const base = mapFieldBaseType(field)
  const tsType = field.isList ? `Array<${base}>` : base
  return field.isRequired ? tsType : `${tsType} | null`
}
```

