      makeField({ name: 'legacy', kind: 'unsupported', type: 'Unsupported', isId: false }),
    ])
    const result = renderModelInterface(model)
    expect(result).not.toContain('legacy')
  })

  it('includes enum fields with the enum type name', () => {
    const model = makeModel('User', [
