      makeField({ name: 'role', kind: 'enum', type: 'Role', isId: false }),
    ])
    const result = renderModelInterface(model)
    expect(result).toContain('role: Role')
  })

  it('renders list fields as Array<T>', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'tags', type: 'String', isList: true, isId: false }),
