    ])
    const result = renderModelInterface(model)
    expect(result).toContain('tags: Array<string> | null')
  })

  it('renders all Prisma scalar types correctly', () => {
    const scalars: Array<[string, string]> = [
      ['String', 'string'],
      ['Boolean', 'boolean'],
      ['Int', 'number'],
      ['Float', 'number'],
      ['BigInt', 'bigint'],
      ['Decimal', 'string'],
      ['DateTime', 'string'],
      ['Json', 'unknown'],
      ['Bytes', 'string'],
    ]
    for (const [prismaType, tsType] of scalars) {
      const model = makeModel('M', [
        makeField({ name: 'id', type: 'Int', isId: true }),
        makeField({ name: 'field', type: prismaType, isId: false }),
