  it('renders an empty interface for a model with no scalar/enum fields', () => {
    const model = makeModel('RelationOnly', [
      makeField({ name: 'posts', kind: 'object', type: 'Post', isId: false }),
    ])
    expect(renderModelInterface(model)).toMatchInlineSnapshot(`
      "export interface RelationOnly {}
      "
    `)
  })
})

