    }
    if (params?.skip !== undefined) {
      url.searchParams.set('skip', String(params.skip))
    }
    const res = await fetch(url.toString())
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User[]>
  }

