    const res = await fetch(`${this.#baseUrl}/users`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User>
  }

  async update(params: { where: { id: number }; data: Partial<User> }): Promise<User> {
    const res = await fetch(`${this.#baseUrl}/users/${params.where.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User>
  }

  async delete(params: { where: { id: number } }): Promise<User> {
    const res = await fetch(`${this.#baseUrl}/users/${params.where.id}`, {
      method: 'DELETE',
    })
    if (!res.ok) {
      throw new Error(`REST API error ${res.status}: ${await res.text()}`)
    }
    return res.json() as Promise<User>
  }
}

