import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'

import { mapPrismaTypeToTs } from './type-mapper'

/**
 * Renders a Prisma enum as a TypeScript union type alias.
 *
 * Example output:
 * ```ts
 * export type Role = 'ADMIN' | 'USER'
 * ```
 */
export function renderEnum(e: DatamodelEnum): string {
  const values = e.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${e.name} = ${values}`
}

/**
 * Returns the TypeScript type string for a single DMMF field, respecting
 * list multiplicity and nullability.
 */
function fieldTsType(field: Field): string {
  let baseType: string
  if (field.kind === 'enum') {
    baseType = field.type
  } else {
    baseType = mapPrismaTypeToTs(field.type)
  }

  if (field.isList) {
    baseType = `${baseType}[]`
  }

  return field.isRequired ? baseType : `${baseType} | null`
}

/**
 * Renders a Prisma model as a TypeScript interface.
 *
 * Only scalar and enum fields are included; relation (`object`) and
 * `unsupported` fields are skipped because they have no meaningful REST
 * representation.
 */
export function renderModelInterface(model: Model): string {
  const fields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const lines = fields.map((f) => `  ${f.name}: ${fieldTsType(f)}`)
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Derives a naive plural REST path segment from a model name.
 *
 * e.g. `User` → `users`, `Category` → `categorys`.
 * An external `pluralize` dependency is intentionally avoided for v1.
 */
function pluralPath(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1) + 's'
}

/**
 * Locates the single `@id` field for a model, or falls back to a synthetic
 * `id: unknown` sentinel for composite `@@id` models.
 */
function primaryKeyField(model: Model): { name: string; type: string; composite: boolean } {
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    return { name: idField.name, type: mapPrismaTypeToTs(idField.type), composite: false }
  }
  return { name: 'id', type: 'unknown', composite: true }
}

/**
 * Renders the per-model CRUD client class with `findMany`, `findUnique`,
 * `create`, `update`, and `delete` methods that call the REST API via the
 * global `fetch`.
 *
 * The `baseUrl` parameter is the value configured in the generator block
 * (e.g. `"/api/v1"`); it is captured in the constructor and used at call
 * time, not baked into the generated strings.
 */
export function renderModelClient(model: Model, baseUrl: string): string {
  const { name: idName, type: idType, composite } = primaryKeyField(model)
  const path = pluralPath(model.name)
  const compositeWarning = composite
    ? `\n  /** WARNING: This model uses a composite @@id — the \`id\` parameter type is unknown. */`
    : ''

  return `export class ${model.name}Client {
  readonly #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(): Promise<${model.name}[]> {
    const res = await fetch(\`\${this.#baseUrl}/${path}\`)
    return res.json() as Promise<${model.name}[]>
  }
${compositeWarning}
  async findUnique(${idName}: ${idType}): Promise<${model.name} | null> {
    const res = await fetch(\`\${this.#baseUrl}/${path}/\${${idName}}\`)
    if (res.status === 404) return null
    return res.json() as Promise<${model.name}>
  }

  async create(data: ${model.name}): Promise<${model.name}> {
    const res = await fetch(\`\${this.#baseUrl}/${path}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return res.json() as Promise<${model.name}>
  }

  async update(${idName}: ${idType}, data: Partial<${model.name}>): Promise<${model.name}> {
    const res = await fetch(\`\${this.#baseUrl}/${path}/\${${idName}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return res.json() as Promise<${model.name}>
  }

  async delete(${idName}: ${idType}): Promise<void> {
    await fetch(\`\${this.#baseUrl}/${path}/\${${idName}}\`, { method: 'DELETE' })
  }
}`
}

/**
 * Renders the top-level `RestApiClient` class that aggregates one typed
 * sub-client per model.
 */
export function renderRestApiClient(modelNames: string[]): string {
  const camel = (n: string) => n.charAt(0).toLowerCase() + n.slice(1)
  const fields = modelNames.map((n) => `  readonly ${camel(n)}: ${n}Client`).join('\n')
  const assignments = modelNames.map((n) => `    this.${camel(n)} = new ${n}Client(baseUrl)`).join('\n')

  return `export class RestApiClient {
${fields}

  constructor(baseUrl: string) {
${assignments}
  }
}`
}

/**
 * Assembles the complete generated file content from the DMMF datamodel,
 * emitting enums, interfaces, per-model clients, and the aggregate
 * `RestApiClient` in order.
 */
export function renderGeneratedFile(enums: readonly DatamodelEnum[], models: readonly Model[], baseUrl: string): string {
  const parts: string[] = [
    '// This file is auto-generated by @prisma/client-generator-rest-api. Do not edit.',
    '',
  ]

  for (const e of enums) {
    parts.push(renderEnum(e))
    parts.push('')
  }

  for (const m of models) {
    parts.push(renderModelInterface(m))
    parts.push('')
  }

  for (const m of models) {
    parts.push(renderModelClient(m, baseUrl))
    parts.push('')
  }

  parts.push(renderRestApiClient(models.map((m) => m.name)))
  parts.push('')

  return parts.join('\n')
}

