import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { renderEnum, renderGeneratedFile, renderModelClient, renderModelInterface, renderRestApiClient } from '../render'

// ────────────────────────── test fixtures ───────────────────────────

function makeField(overrides: Partial<Field>): Field {
  return {
    kind: 'scalar',
    name: 'id',
    isRequired: true,
    isList: false,
    isUnique: true,
    isId: true,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    dbName: null,
    ...overrides,
  } as Field
}

function makeModel(name: string, fields: Field[], primaryKey: Model['primaryKey'] = null): Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey,
  } as unknown as Model
}

// ──────────────────────────── renderEnum ────────────────────────────

describe('renderEnum', () => {
  test('renders a two-value enum as a union type alias', () => {
    const e: DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    }
    expect(renderEnum(e)).toBe("export type Role = 'ADMIN' | 'USER'")
  })

  test('renders a single-value enum', () => {
    const e: DatamodelEnum = { name: 'Status', values: [{ name: 'ACTIVE', dbName: null }] }
    expect(renderEnum(e)).toBe("export type Status = 'ACTIVE'")
  })

  test('renders a three-value enum with pipe separators', () => {
    const e: DatamodelEnum = {
      name: 'Color',
      values: [
        { name: 'RED', dbName: null },
        { name: 'GREEN', dbName: null },
        { name: 'BLUE', dbName: null },
      ],
    }
    expect(renderEnum(e)).toBe("export type Color = 'RED' | 'GREEN' | 'BLUE'")
  })
})

// ──────────────────────── renderModelInterface ───────────────────────

describe('renderModelInterface', () => {
  test('opens with the correct interface declaration', () => {
    const model = makeModel('User', [makeField({ name: 'id', type: 'String', isId: true })])
    expect(renderModelInterface(model)).toContain('export interface User {')
  })

  test('maps String to string', () => {
    const model = makeModel('User', [makeField({ name: 'name', type: 'String', isId: false })])
    expect(renderModelInterface(model)).toContain('  name: string')
  })

  test('maps Int and Float to number', () => {
    const model = makeModel('Item', [
      makeField({ name: 'count', type: 'Int', isId: false }),
      makeField({ name: 'price', type: 'Float', isId: false }),
    ])
    const result = renderModelInterface(model)
    expect(result).toContain('  count: number')
    expect(result).toContain('  price: number')
  })

  test('maps BigInt to bigint', () => {
    const model = makeModel('Payment', [makeField({ name: 'amount', type: 'BigInt', isId: false })])
    expect(renderModelInterface(model)).toContain('  amount: bigint')
  })

  test('maps Decimal and DateTime to string', () => {
    const model = makeModel('Event', [
      makeField({ name: 'price', type: 'Decimal', isId: false }),
      makeField({ name: 'createdAt', type: 'DateTime', isId: false }),
    ])
    const result = renderModelInterface(model)
    expect(result).toContain('  price: string')
    expect(result).toContain('  createdAt: string')
  })

  test('maps Json to unknown', () => {
    const model = makeModel('Config', [makeField({ name: 'data', type: 'Json', isId: false })])
    expect(renderModelInterface(model)).toContain('  data: unknown')
  })

  test('appends | null for optional fields', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'subtitle', type: 'String', isRequired: false, isId: false }),
    ])
    expect(renderModelInterface(model)).toContain('  subtitle: string | null')
  })

  test('appends [] for list fields', () => {
    const model = makeModel('Tag', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'aliases', type: 'String', isList: true, isId: false }),
    ])
    expect(renderModelInterface(model)).toContain('  aliases: string[]')
  })

  test('skips relation (object) fields', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'String', isId: true }),
      makeField({ name: 'author', type: 'User', kind: 'object', isId: false }),
    ])
    expect(renderModelInterface(model)).not.toContain('author')
  })

  test('skips unsupported fields', () => {
    const model = makeModel('Weird', [
      makeField({ name: 'id', type: 'String', isId: true }),
      makeField({ name: 'geometry', type: 'Unsupported', kind: 'unsupported', isId: false }),
    ])
    expect(renderModelInterface(model)).not.toContain('geometry')
  })

  test('includes enum-kind fields using the enum name as type', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'String', isId: true }),
      makeField({ name: 'role', type: 'Role', kind: 'enum', isId: false }),
    ])
    expect(renderModelInterface(model)).toContain('  role: Role')
  })
})

// ─────────────────────── renderModelClient ──────────────────────────

describe('renderModelClient', () => {
  const userModel = makeModel('User', [
    makeField({ name: 'id', type: 'String', isId: true }),
    makeField({ name: 'name', type: 'String', isId: false }),
  ])

  test('renders the class declaration', () => {
    expect(renderModelClient(userModel, '/api')).toContain('export class UserClient {')
  })

  test('uses a private #baseUrl field', () => {
    expect(renderModelClient(userModel, '/api')).toContain('readonly #baseUrl: string')
  })

  test('renders findMany returning a typed array', () => {
    const result = renderModelClient(userModel, '/api')
    expect(result).toContain('async findMany(): Promise<User[]>')
    expect(result).toContain('`${this.#baseUrl}/users`')
  })

  test('renders findUnique with the @id field name and type', () => {
    const result = renderModelClient(userModel, '/api')
    expect(result).toContain('async findUnique(id: string): Promise<User | null>')
    expect(result).toContain('if (res.status === 404) return null')
  })

  test('renders create with POST method', () => {
    const result = renderModelClient(userModel, '/api')
    expect(result).toContain('async create(data: User): Promise<User>')
    expect(result).toContain("method: 'POST'")
  })

  test('renders update with PATCH method and Partial type', () => {
    const result = renderModelClient(userModel, '/api')
    expect(result).toContain('async update(id: string, data: Partial<User>): Promise<User>')
    expect(result).toContain("method: 'PATCH'")
  })

  test('renders delete with DELETE method returning void', () => {
    const result = renderModelClient(userModel, '/api')
    expect(result).toContain('async delete(id: string): Promise<void>')
    expect(result).toContain("method: 'DELETE'")
  })

  test('adds composite @@id warning when no @id field is present', () => {
    const compositeModel = makeModel('Composite', [
      makeField({ name: 'a', type: 'String', isId: false }),
      makeField({ name: 'b', type: 'String', isId: false }),
    ])
    const result = renderModelClient(compositeModel, '/api')
    expect(result).toContain('WARNING: This model uses a composite @@id')
    expect(result).toContain('id: unknown')
  })

  test('uses the model name lowercased as the REST path segment', () => {
    const postModel = makeModel('Post', [makeField({ name: 'id', type: 'Int', isId: true })])
    expect(renderModelClient(postModel, '/api')).toContain('/posts')
  })
})

// ─────────────────────── renderRestApiClient ────────────────────────

describe('renderRestApiClient', () => {
  test('renders the class declaration', () => {
    expect(renderRestApiClient(['User'])).toContain('export class RestApiClient {')
  })

  test('renders a readonly field per model, camel-cased', () => {
    const result = renderRestApiClient(['User', 'Post'])
    expect(result).toContain('readonly user: UserClient')
    expect(result).toContain('readonly post: PostClient')
  })

  test('assigns each sub-client in the constructor', () => {
    const result = renderRestApiClient(['User', 'Post'])
    expect(result).toContain('this.user = new UserClient(baseUrl)')
    expect(result).toContain('this.post = new PostClient(baseUrl)')
  })

  test('accepts a baseUrl constructor parameter', () => {
    expect(renderRestApiClient(['Item'])).toContain('constructor(baseUrl: string)')
  })

  test('renders an empty-body class when given no models', () => {
    const result = renderRestApiClient([])
    expect(result).toContain('export class RestApiClient {')
    expect(result).toContain('constructor(baseUrl: string)')
  })
})

// ────────────────────── renderGeneratedFile ─────────────────────────

describe('renderGeneratedFile', () => {
  test('begins with the auto-generated banner comment', () => {
    const result = renderGeneratedFile([], [], '/api')
    expect(result.startsWith('// This file is auto-generated by @prisma/client-generator-rest-api')).toBe(true)
  })

  test('includes a rendered enum when one is provided', () => {
    const e: DatamodelEnum = { name: 'Role', values: [{ name: 'ADMIN', dbName: null }] }
    const result = renderGeneratedFile([e], [], '/api')
    expect(result).toContain("export type Role = 'ADMIN'")
  })

  test('includes the model interface, model client, and aggregate client', () => {
    const model = makeModel('User', [makeField({ name: 'id', type: 'String', isId: true })])
    const result = renderGeneratedFile([], [model], '/api')
    expect(result).toContain('export interface User {')
    expect(result).toContain('export class UserClient {')
    expect(result).toContain('export class RestApiClient {')
  })

  test('enums appear before interfaces in the output', () => {
    const e: DatamodelEnum = { name: 'Role', values: [{ name: 'ADMIN', dbName: null }] }
    const model = makeModel('User', [makeField({ name: 'id', type: 'String', isId: true })])
    const result = renderGeneratedFile([e], [model], '/api')
    expect(result.indexOf('export type Role')).toBeLessThan(result.indexOf('export interface User'))
  })

  test('interfaces appear before model clients in the output', () => {
    const model = makeModel('User', [makeField({ name: 'id', type: 'String', isId: true })])
    const result = renderGeneratedFile([], [model], '/api')
    expect(result.indexOf('export interface User')).toBeLessThan(result.indexOf('export class UserClient'))
  })
})

